interceptor.preaction:

						String measure_dt = rrequest.getStringAttribute("MEASURE_DT", "");// 取出输入的查询时间
						System.out.println("measure_dt:" + measure_dt);
						if (measure_dt.equals("")) 
						{
							Connection conn = rrequest.getConnection();
							PreparedStatement pstmt = null;
							try {
									String SQL = "Select DATA_DT from IBS.T8_DATA_DT";
									pstmt = conn.prepareStatement(SQL);
									ResultSet resultSet = pstmt.executeQuery();
									while (resultSet.next()) {
					                     String date=resultSet.getString("DATA_DT");
					                     rrequest.setAttribute("MEASURE_DT", date);
										 measure_dt=date;
				                    }
									System.out.println("measure_dt处理后时间为:" + measure_dt);
									resultSet.close();
									pstmt.close();
								} 
							catch (Exception e) {
									e.printStackTrace();
							}
                        }

